-- {"operators": "INNER_JOIN,AGGREGATE,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": false, "tables": "ITEM,STOCK,ORDER_LINE", "ducklake": true}
WITH item_rev AS (SELECT ol.OL_I_ID, SUM(ol.OL_AMOUNT) AS rev FROM dl.ORDER_LINE ol GROUP BY ol.OL_I_ID), item_stock AS (SELECT S_I_ID, SUM(S_QUANTITY) AS total_stock FROM dl.STOCK GROUP BY S_I_ID) SELECT i.I_ID, i.I_NAME, i.I_PRICE, ir.rev, its.total_stock, (ir.rev / NULLIF(its.total_stock, 0)) AS rev_per_stock FROM dl.ITEM i JOIN item_rev ir ON i.I_ID = ir.OL_I_ID JOIN item_stock its ON i.I_ID = its.S_I_ID;
